import{_ as o,a,a3 as i,o as t}from"./chunks/framework.edeurCMZ.js";const p=JSON.parse('{"title":"Azure Tips and Tricks","description":"","frontmatter":{},"headers":[],"relativePath":"devdoc/userdoc/azure/TipsAndTricks.md","filePath":"devdoc/userdoc/azure/TipsAndTricks.md","lastUpdated":1782747484000}'),r={name:"devdoc/userdoc/azure/TipsAndTricks.md"};function l(d,e,s,n,c,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="azure-tips-and-tricks" tabindex="-1">Azure Tips and Tricks <a class="header-anchor" href="#azure-tips-and-tricks" aria-label="Permalink to &quot;Azure Tips and Tricks&quot;">​</a></h1><p>The following section provides useful suggestions, searches, actions, hints, and prompts to help with navigating and working with Azure, the Azure CLI, and portal.azure.com. This is a living document that will continue to be updated as we expand our cloud journey.</p><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#view-resource-groups">View Resource Groups</a></li><li><a href="#view-event-details">View Event Details</a></li><li><a href="#create-a-dashboard-in-azure">Create a Dashboard in Azure</a></li></ul><hr><h2 id="view-resource-groups" tabindex="-1">View Resource Groups <a class="header-anchor" href="#view-resource-groups" aria-label="Permalink to &quot;View Resource Groups&quot;">​</a></h2><p>To see resource groups in the Azure portal:</p><ol><li>Go to the resource group service page: <a href="https://portal.azure.com/#view/HubsExtension/BrowseResourceGroups" target="_blank" rel="noreferrer">https://portal.azure.com/#view/HubsExtension/BrowseResourceGroups</a></li><li>Click <code>Add filter</code></li><li>Filter on <code>Admin</code></li><li>Set the Value to <code>ALL</code> or select any names you are interested in</li></ol><p><strong>Note</strong>: The names in the list are the only ones that have the Admin tag set. You can also specify to filter on other fields from there.</p><hr><h2 id="view-event-details" tabindex="-1">View Event Details <a class="header-anchor" href="#view-event-details" aria-label="Permalink to &quot;View Event Details&quot;">​</a></h2><p>To find who initiated an event or view activity logs:</p><ol><li>On the left-hand panel when viewing a resource group, select <code>Activity Log</code></li><li>Select <code>Add filter</code> → <code>Event Initiated by</code></li><li>Adjust the timespan filter as necessary to view the event</li></ol><p><strong>Tip</strong>: You can optionally add an <code>Event category = Administrative</code> filter for more specific results.</p><hr><h2 id="create-a-dashboard-in-azure" tabindex="-1">Create a Dashboard in Azure <a class="header-anchor" href="#create-a-dashboard-in-azure" aria-label="Permalink to &quot;Create a Dashboard in Azure&quot;">​</a></h2><p>To create a custom dashboard in Azure:</p><ol><li>Login to the Azure portal</li><li>Click on the <code>hamburger icon</code> (located at the top left corner of the page)</li><li>Select <code>Dashboard</code> to go to your dashboards</li><li>Click <code>Create</code> (top left corner)</li><li>Click on the <code>Custom</code> tile</li><li>Edit the input box and provide a name for your dashboard</li><li>Click on <code>Resource groups</code> in the tile gallery</li><li>Click <code>Add</code></li><li>Click and drag the <code>lower right corner</code> of the tile to resize it to your liking</li><li>Click <code>Save</code> to save your settings</li></ol><p>You should now be taken to your new dashboard.</p><h3 id="configure-dashboard-filters" tabindex="-1">Configure Dashboard Filters <a class="header-anchor" href="#configure-dashboard-filters" aria-label="Permalink to &quot;Configure Dashboard Filters&quot;">​</a></h3><p>To filter your dashboard by admin/owner:</p><ol><li>Click on your new dashboard tile</li><li>Click on <code>Add filter</code> (located at the top center of the page)</li><li>Click on the <code>Filter</code> input box to reveal the tags</li><li>Select the <code>Admin</code> tag</li><li>Click on the <code>Value</code> input box</li><li>Click on <code>Select all</code> to unselect all</li><li>Select your name</li><li>Click on <code>Apply</code></li></ol><h3 id="save-dashboard-view" tabindex="-1">Save Dashboard View <a class="header-anchor" href="#save-dashboard-view" aria-label="Permalink to &quot;Save Dashboard View&quot;">​</a></h3><p>To save your customized dashboard view:</p><ol><li>Click on <code>Manage view</code> (located at the top left of the page)</li><li>Select <code>Save view</code></li><li>Enter a name for the view in the input box</li><li>Click <code>Save</code></li></ol><hr><p><em>This document will be updated regularly with additional tips and tricks as we continue our Azure journey.</em></p>',27)])])}const f=o(r,[["render",l]]);export{p as __pageData,f as default};
